assign(paste0("RS", RS, "_2023_SINAN_AGRO"), 
       SINAN_IEXOGNET_RS) 

write.csv(SINAN_IEXOGNET_RS,
          "/home/gustavo/Área de trabalho/Intox.csv",
          row.names = FALSE)

